+        &self.dense_shape
+    }
+
+    #[must_use]
+    pub fn sparse_dim(&self) -> usize {
+        self.sparse_dim
+    }
+
+    #[must_use]
+    pub fn nnz(&self) -> usize {
+        self.indices.meta().shape().get(1).copied().unwrap_or(0)
+    }
+
+    #[must_use]
+    pub fn is_coalesced(&self) -> bool {
+        self.coalesced
+    }
+
